  /**
   * creates a new IdeaEnvironment or returns the cached one
   * 
   * @deprecated Code that needs access to functionality of an Environment shall get its value configured from outside and not attempt to create one. The code that starts an environment doesn't need to re-use a cached instance.
   */
  @NotNull
  @Deprecated
  @ToRemove(version = 2018.1)
  public static Environment getOrCreate(@NotNull EnvironmentConfig config) {
    Environment currentEnv = EnvironmentContainer.get();
    if (currentEnv != null) {
      if (!(currentEnv instanceof IdeaEnvironment)) {
        throw new IllegalStateException("Still no support for interchanging lightweight and heavyweight environments");
      }
      currentEnv.retain();
      return currentEnv;
    } else {
      IdeaEnvironment ideaEnv = new IdeaEnvironment(config);
      ideaEnv.init();
      EnvironmentContainer.setCurrent(ideaEnv);
      assert EnvironmentContainer.get() == ideaEnv;
      return ideaEnv;
    }
  }

  public void init() {
    if (LOG.isInfoEnabled()) {
      LOG.info("Creating IDEA environment");
    }

    System.setProperty("idea.is.internal", InternalFlag.isInternalMode() + "");
    System.setProperty("idea.no.jre.check", "true");
    System.setProperty("idea.load.plugins", "true");

    addRequiredPlugins(myConfig);

    myIdeaApplication = createIdeaTestApp();
    disallowAccessToClosedProjectsDir();

    MPSCoreComponents coreComponents = getMPSCoreComponents();
    super.init(coreComponents.getPlatform());
  }

  private void addRequiredPlugins(EnvironmentConfig config) {
    // [MM]: looks like a hack, should we regenerate it to a regular plugin specification?  
    // Probably, with plugin-set-ref to ensure the same plugin set is used 

    // typically, this property is set by generated ant scripts before running tests 
    if (isNotEmptyString(System.getProperty(PLUGINS_PATH))) {
      return;
    }

    // otherwise, we set it from config 
    setPluginPathProperty();
    setPluginIdsPropertyFromConfig(config);
  }

  private void setPluginPathProperty() {
    // [MM]: why do we set ids from config, while path is not config-related? 
    StringBuilder pluginPath = new StringBuilder();
    File pluginDir = new File(PathManager.getPreInstalledPluginsPath());
    if (pluginDir.exists()) {
      for (File pluginFolder : pluginDir.listFiles()) {
        if (pluginPath.length() > 0) {
          pluginPath.append(File.pathSeparator);
        }
        pluginPath.append(pluginFolder.getPath());
      }
    }
    for (PluginDescriptor pd : myConfig.getPlugins()) {
      if (pd.getPath().startsWith(PathManager.getPreInstalledPluginsPath())) {
        continue;
      }
      if (pluginPath.length() > 0) {
        pluginPath.append(File.pathSeparator);
      }
      pluginPath.append(pd.getPath());
    }
    System.setProperty(PLUGINS_PATH, pluginPath.toString());
  }

  private void setPluginIdsPropertyFromConfig(EnvironmentConfig config) {
    StringBuilder result = new StringBuilder();
    Set<PluginDescriptor> plugins = config.getPlugins();
    if (plugins == null) {
      return;
    }
    for (PluginDescriptor plugin : SetSequence.fromSet(plugins)) {
      assert plugin.getId() != null : "id should be specified for plugin " + plugin.getPath();
      result.append(plugin.getId());
      result.append(",");
    }
    System.setProperty("idea.load.plugins.id", result.toString());
  }

  private void disallowAccessToClosedProjectsDir() {
    if (RuntimeFlags.isTestMode()) {
      ProjectManager.getInstance().addProjectManagerListener(new ProjectManagerAdapter() {
        @Override
        public void projectClosed(Project project) {
          String basePath = project.getBasePath();
          if (basePath != null) {
            VfsRootAccess.disallowRootAccess(basePath);
          }
        }
      });
    }
  }

  private MPSCoreComponents getMPSCoreComponents() {
    return ApplicationManager.getApplication().getComponent(MPSCoreComponents.class);
  }

  private IdeaTestApplication createIdeaTestApp() {
    if (LOG.isInfoEnabled()) {
      LOG.info("Creating IdeaTestApplication");
    }
    return IdeaTestApplication.getInstance();
  }

  @Override
  @NotNull
  public jetbrains.mps.project.Project doOpenProject(@NotNull File projectFile) {
    if (RuntimeFlags.isTestMode()) {
      // for ant tests we run with the flag, which disables those checks 
      VfsRootAccess.allowRootAccess(projectFile.getAbsolutePath());
    }
    return openProjectInIdeaEnvironment(projectFile);
  }

  @NotNull
  @Override
  public jetbrains.mps.project.Project createEmptyProject() {
    checkInitialized();
    if (LOG.isInfoEnabled()) {
      LOG.info("Creating an empty project");
    }
    File dummyProjectFile = createDummyProjectFile();
    jetbrains.mps.project.Project dummyProject = openProject(dummyProjectFile);
    return dummyProject;
  }

  @Override
  public void doDispose() {
    ApplicationManager.getApplication().invokeAndWait(new Runnable() {
      @Override
      public void run() {
        List<jetbrains.mps.project.Project> openedProjects = new ArrayList<jetbrains.mps.project.Project>(jetbrains.mps.project.ProjectManager.getInstance().getOpenedProjects());
        for (final jetbrains.mps.project.Project project : openedProjects) {
          if (project instanceof MPSProject) {
            // MPSProject need to be disposed outside writeAction to prevent exception: 
            // java.lang.IllegalStateException: Must not call closeProject() from under write action  
            // because fireProjectClosing() listeners must have a chance to do something useful 
            // TODO: find way to put MPSProject#dispose() under writeAction 
            project.dispose();
          } else {
            ApplicationManager.getApplication().runWriteAction(new Runnable() {
              public void run() {
                project.dispose();
              }
            });
          }
        }
        ApplicationManager.getApplication().runWriteAction(new Runnable() {
          public void run() {
            myIdeaApplication.dispose();
          }
        });
      }
    }, ModalityState.NON_MODAL);
  }

  private File createDummyProjectFile() {
    File dummyProjDir = FileUtil.createTmpDir();
    File dotMps = new File(dummyProjDir, Project.DIRECTORY_STORE_FOLDER);
    dotMps.mkdir();
    dummyProjDir.deleteOnExit();
    return dummyProjDir;
  }

  @NotNull
  private jetbrains.mps.project.Project openProjectInIdeaEnvironment(File projectFile) {
    if (!(projectFile.exists())) {
      throw new IdeaEnvironment.ProjectDirectoryDoesNotExistException(projectFile.getAbsolutePath());
    }
    final ProjectManagerEx projectManager = ProjectManagerEx.getInstanceEx();
    final String filePath = projectFile.getAbsolutePath();

    final Reference<Project> project = new Reference<Project>();
    final Reference<Exception> exc = new Reference<Exception>();
    ApplicationManager.getApplication().invokeAndWait(new Runnable() {
      public void run() {
        try {
          if (LOG.isInfoEnabled()) {
            LOG.info("Load and open the project with path '" + filePath + "'");
          }
          project.set(projectManager.loadAndOpenProject(filePath));
          refreshProjectDir(project.get());
        } catch (Exception e) {
          exc.set(e);
        }
      }
    }, ModalityState.NON_MODAL);

    if (!(exc.isNull())) {
      throw new IdeaEnvironment.CouldNotLoadProjectException(String.format("ProjectManager could not load project from '%s'", projectFile.getAbsolutePath()), exc.get());
    }

    if (project.isNull()) {
      throw new IdeaEnvironment.ProjectCouldNotBeOpenedException(String.format("Could not open project (null in return) from the '%s'", projectFile.getAbsolutePath()), exc.get());
    }

    final IdeaEnvironment.PostStartupActivitiesWaiter waiter = new IdeaEnvironment.PostStartupActivitiesWaiter(project.get());
    ApplicationManager.getApplication().invokeAndWait(new Runnable() {
      public void run() {
        waiter.init();
      }
    });

    waiter.wait0();

    return project.get().getComponent(MPSProject.class);
  }

  private void refreshProjectDir(@NotNull Project project) {
    // calling sync refresh for FS in order to update all modules/models loaded from the project 
    // if unit-test is executed with the "reuse caches" option. 
    String basePath = project.getBasePath();
    if (basePath != null) {
      CachingFileSystem fs = ApplicationManager.getApplication().getComponent(IdeaFileSystem.class);
      fs.getFile(basePath).refresh(new DefaultCachingContext(true, true));
    }
  }

  /**
   * BIG GUN
   * Only use when absolutely necessary.
   * Please wrap an invocation of this method into a method which is clear what it waits for
   * For instance if you wait for the end of poststartup activities -- extract a new method
   * #waitForPostStartupActivitiesToEnd.
   * 
   * Otherwise it will be hard to perceive what exactly your code waits for
   */
  @Override
  public void flushAllEvents() {
    checkInitialized();
    ApplicationManager.getApplication().invokeAndWait(new Runnable() {
      public void run() {
        try {
          PlatformTestUtil.dispatchAllEventsInIdeEventQueue();
        } catch (InterruptedException e) {
          throw new EnvironmentSetupException("Interrupted", e) {};
        }
      }
    }, ModalityState.NON_MODAL);
    ModelAccess.instance().flushEventQueue();
  }

  @Override
  public Platform getPlatform() {
    return getMPSCoreComponents().getPlatform();
  }

  private static final class PostStartupActivitiesWaiter {
    private final Semaphore mySem = new Semaphore(0);
    private final Project myProject;

    public PostStartupActivitiesWaiter(@NotNull Project project) {
      myProject = project;
    }

    public void init() {
      if (getStartupManager().postStartupActivityPassed()) {
        return;
      }
      getStartupManager().registerPostStartupActivity(new Runnable() {
        public void run() {
          mySem.release();
        }
      });
    }

    private StartupManagerEx getStartupManager() {
      return StartupManagerEx.getInstanceEx(myProject);
    }

    public void wait0() {
      StartupManagerEx startupManager = getStartupManager();
      if (startupManager.postStartupActivityPassed()) {
        return;
      }
      try {
        mySem.acquire();
      } catch (InterruptedException e) {
        throw new IdeaEnvironment.InterruptedWhileWaitingForPostStartupException("Caught exception while waiting for the post startup activities", e);
      }
      waitForDumbModeToFinish();
      assert startupManager.postStartupActivityPassed();
    }

    private void waitForDumbModeToFinish() {
      final StartupManagerEx startupManager = getStartupManager();
      if (!(startupManager.postStartupActivityPassed())) {
        DumbService.getInstance(myProject).runWhenSmart(new Runnable() {
          public void run() {
            if (!(startupManager.postStartupActivityPassed())) {
              waitForDumbModeToFinish();
            }
          }
        });
      }
    }
  }

